function buildAuthHeaders(opts) {
  if (opts.apiKey) {
    return { "X-Goog-Api-Key": opts.apiKey };
  }
  if (opts.accessToken) {
    const headers = {
      Authorization: `Bearer ${opts.accessToken}`
    };
    if (opts.quotaProjectId) {
      headers["X-Goog-User-Project"] = opts.quotaProjectId;
    }
    return headers;
  }
  throw new Error("No authentication credentials provided. Supply either apiKey or accessToken.");
}

